// let's imagine this file is autogenerated from the backend
// ideally, we want to keep these api related types in sync
// with the backend instead of manually writing them out
import { type Member, type Replycant } from "./tables/forTables";

export type BaseEntity = {
    id: string;
    createdAt: number;
};

export interface AuthTokenResponse {
    access_token: string;
    token_type: string;
}

export type Entity<T> = {
    [K in keyof T]: T[K];
} & BaseEntity;

export type User = Entity<{
    id: number;
    first_name: string;
    last_name: string;
    middle_name: string;
    email: string;
}>;

export type LoginResponse = {
    access_token: string;
    token_type: string;
};

export type Space = {
    id: number;
    title: string;
    projectsCount: number;
    membersCount: number;
    color: string;
    category: string;
    description: string;
};

export type Project = {
    id: number;
    tag: string;
    tagVariant:
        | "error"
        | "type"
        | "disabled"
        | "default"
        | "info"
        | "warning"
        | "success"
        | "secondary"
        | undefined;
    title: string;
    description: string;
    progressValue: number;
    dateText: string;
    tags: { text: string }[];
    membersCount: number;
    users: { name: string }[];
    archived: boolean;
};

export type ProjectRole = {
    title: string;
    tasks: string[];
    count: number;
};

export interface ProjectSingle extends Project {
    spaceId: number;
    descriptionExtended: string;
    creationDate: string;
    color: string;
    roles: ProjectRole[];
    members?: Member[];
    replycants?: Replycant[];
}

export type SpacesListResponce = {
    categories: { name: string }[];
    spaces: Space[];
    role: "root" | "admin" | "manager" | "member";
};

export type NotificationType = "mention" | "request" | "join";

export interface Notification {
    id: number;
    type: NotificationType;
    name: string;
    action: string;
    project: string;
    time: string;
    avatar: string;
    read: boolean;
}

// ========== ДОСКА ==========

export interface ApiBoard {
    project_id: number;
    project_name: string;
    columns: ApiColumnWithTasksAndSubtasks[];
}

// ========== КОЛОНКА ==========

export interface ApiColumn {
    id: number;
    project_id: number;
    name: string;
    color: string;
    position: number;
    wip_limit?: number;
    created_at: string;
    updated_at: string;
}

export interface ApiColumnWithTasksAndSubtasks extends ApiColumn {
    tasks: ApiTaskWithSubtasks[];
    task_count: number;
}

// ========== ЗАДАЧИ ==========

export type ApiTaskPriority = "default" | "low" | "medium" | "high" | "urgent";

export interface ApiTask {
    id: number;
    title: string;
    description?: string;
    priority?: ApiTaskPriority;
    position: number;
    column_id: number;
    project_id: number;
    created_by_id: number;
    assignees: User[];
    created_by?: User;
    due_date?: string;
    tags?: string;
    created_at: string;
    updated_at: string;
}

export interface ApiTaskWithSubtasks extends ApiTask {
    subtasks?: ApiSubtask[];
    subtask_count?: number;
}

// ========== ПОДЗАДАЧИ ==========

export interface ApiSubtask {
    id: number;
    task_id: number;
    title: string;
    is_completed: boolean;
    position: number;
    created_by_id: number;
    created_by?: User;
    created_at: string;
    updated_at: string;
}

export interface ApiSubtaskListResponse {
    items: ApiSubtask[];
    total: number;
}

// ========== ИСТОРИЯ ==========

export interface ApiTaskHistory {
    id: number;
    task_id: number;
    changed_by: User;
    old_column_id?: number;
    new_column_id?: number;
    change_type: string;
    change_data?: Record<string, unknown>;
    created_at: string;
}

// ========== СТАТИСТИКА ==========

export interface ApiProjectStats {
    total: number;
    by_column: Record<number, number>;
    by_priority: {
        low: number;
        medium: number;
        high: number;
        urgent: number;
    };
    overdue: number;
    without_assignee: number;
    column_names: Record<number, string>;
}
